import{_ as e,o as t,c as a,b as s}from"./app.65bc8a5c.js";var r="/assets/sun.eb1a04e4.svg",o="/assets/sun-granules.ac706b47.jpg",i="/assets/Sunspot.aeba8507.jpg",n="/assets/extreme_ultraviolet_sun.d0b00a61.jpg";const S=JSON.parse('{"title":"The Sun","description":"","frontmatter":{"title":"The Sun","subtitle":"The Sun is the center of our Solar system and is the main source of all light on Earth.","date":"2021-08-30T00:00:00.000Z","cover":"sun.jpg"},"headers":[{"level":2,"title":"UV radiation of the Sun","slug":"uv-radiation-of-the-sun"}],"relativePath":"theory/color/light/sun/index.md"}'),h={name:"theory/color/light/sun/index.md"},u=s('<p>The Sun is the center of our Solar system and is the main source of all light on Earth.</p><p>The Sun is a G-type main-sequence star that comprises about 99.86% of the mass of the Solar System. The Sun has an absolute magnitude of +4.83, estimated to be brighter than about 85% of the stars in the Milky Way, most of which are red dwarfs.</p><p><img src="'+r+'" alt="svg"></p><p>The Sun is by far the brightest object in the Earth&#39;s sky, with an apparent magnitude of \u221226.74. This is about 13 billion times brighter than the next brightest star, Sirius, which has an apparent magnitude of \u22121.46.</p><p>Thermonuclear reactions in its core produce high energy gamma-rays that are absorbed and converted into lower energy radiation by ionized atoms in its photosphere and chromosphere layers.</p><p><img src="'+o+'" alt=""></p><p><img src="'+i+'" alt=""></p><h2 id="uv-radiation-of-the-sun" tabindex="-1">UV radiation of the Sun <a class="header-anchor" href="#uv-radiation-of-the-sun" aria-hidden="true">#</a></h2><p><img src="'+n+'" alt=""></p>',9),p=[u];function c(d,l,_,m,g,f){return t(),a("div",null,p)}var v=e(h,[["render",c]]);export{S as __pageData,v as default};
